import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Users, Roles, and Permissions","description":"Role-based access control (RBAC) for Krado One — built-in roles, custom roles, and fine-grained portal permissions.","frontmatter":{"title":"Users, Roles, and Permissions","description":"Role-based access control (RBAC) for Krado One — built-in roles, custom roles, and fine-grained portal permissions."},"headers":[],"relativePath":"admin/users-and-roles.md","filePath":"admin/users-and-roles.md"}'),o={name:"admin/users-and-roles.md"};function s(i,t,n,c,l,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="users-roles-and-permissions" tabindex="-1">Users, roles, and permissions <a class="header-anchor" href="#users-roles-and-permissions" aria-label="Permalink to &quot;Users, roles, and permissions&quot;">​</a></h1><p>DevX uses role-based access control (RBAC). Every user has a role that defines which portals they can access and what they can do inside each one.</p><p><strong>Configure in:</strong> Portal Config → Users / Roles &amp; Permissions</p><hr><h2 id="built-in-roles" tabindex="-1">Built-in roles <a class="header-anchor" href="#built-in-roles" aria-label="Permalink to &quot;Built-in roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Description</th></tr></thead><tbody><tr><td><strong>admin</strong></td><td>Full access to all portals and Portal Config</td></tr><tr><td><strong>developer</strong></td><td>Access to Task, DRM, DevX, Runbook, and Platform portals (read + write)</td></tr><tr><td><strong>viewer</strong></td><td>Read-only access to portals they are granted access to</td></tr></tbody></table><p>Built-in roles cannot be deleted but their descriptions can be edited.</p><hr><h2 id="custom-roles" tabindex="-1">Custom roles <a class="header-anchor" href="#custom-roles" aria-label="Permalink to &quot;Custom roles&quot;">​</a></h2><p>Go to <strong>Portal Config → Roles &amp; Permissions → New Role</strong>.</p><h3 id="system-permissions" tabindex="-1">System permissions <a class="header-anchor" href="#system-permissions" aria-label="Permalink to &quot;System permissions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Permission</th><th>Description</th></tr></thead><tbody><tr><td><code>portal_access</code></td><td>Can log in. Disable to create reference-only roles</td></tr><tr><td><code>manage_users</code></td><td>Can create, edit, and delete users</td></tr><tr><td><code>manage_config</code></td><td>Can access Portal Config</td></tr></tbody></table><h3 id="portal-access-flags" tabindex="-1">Portal access flags <a class="header-anchor" href="#portal-access-flags" aria-label="Permalink to &quot;Portal access flags&quot;">​</a></h3><p>Control which portals this role can enter:</p><table tabindex="0"><thead><tr><th>Flag</th><th>Portal</th></tr></thead><tbody><tr><td><code>access_tasks</code></td><td>Task Management</td></tr><tr><td><code>access_drm</code></td><td>DRM Portal</td></tr><tr><td><code>access_idp</code></td><td>DevX Portal</td></tr><tr><td><code>access_runbooks</code></td><td>Runbook Portal</td></tr><tr><td><code>access_cloud</code></td><td>Cloud &amp; FinOps</td></tr><tr><td><code>access_security</code></td><td>Security &amp; Compliance</td></tr><tr><td><code>access_platform</code></td><td>Platform Engineering</td></tr></tbody></table><h3 id="write-access-flags" tabindex="-1">Write access flags <a class="header-anchor" href="#write-access-flags" aria-label="Permalink to &quot;Write access flags&quot;">​</a></h3><p>Control whether the role can create/edit/delete within each portal:</p><table tabindex="0"><thead><tr><th>Flag</th><th>Portal</th></tr></thead><tbody><tr><td><code>write_tasks</code></td><td>Task Management</td></tr><tr><td><code>write_drm</code></td><td>DRM Portal</td></tr><tr><td><code>write_idp</code></td><td>DevX Portal</td></tr><tr><td><code>write_runbooks</code></td><td>Runbook Portal</td></tr><tr><td><code>write_cloud</code></td><td>Cloud &amp; FinOps</td></tr><tr><td><code>write_security</code></td><td>Security &amp; Compliance</td></tr><tr><td><code>write_platform</code></td><td>Platform Engineering</td></tr></tbody></table><h3 id="resource-level-permissions" tabindex="-1">Resource-level permissions <a class="header-anchor" href="#resource-level-permissions" aria-label="Permalink to &quot;Resource-level permissions&quot;">​</a></h3><p>Fine-grained <code>view / create / edit / delete</code> control per resource:</p><table tabindex="0"><thead><tr><th>Resource</th><th>Description</th></tr></thead><tbody><tr><td><code>tasks</code></td><td>Task records</td></tr><tr><td><code>drm</code></td><td>Incidents and DRM catalog</td></tr><tr><td><code>service_catalog</code></td><td>Service Catalog entries (DevX)</td></tr><tr><td><code>runbooks</code></td><td>Runbook definitions and executions</td></tr><tr><td><code>cloud</code></td><td>Cloud resources and FinOps data</td></tr><tr><td><code>security</code></td><td>Vulnerabilities, secrets, compliance</td></tr><tr><td><code>platform</code></td><td>Platform Engineering resources</td></tr></tbody></table><hr><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><h3 id="creating-a-user" tabindex="-1">Creating a user <a class="header-anchor" href="#creating-a-user" aria-label="Permalink to &quot;Creating a user&quot;">​</a></h3><p>Go to <strong>Portal Config → Users → Add User</strong>. Fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Username</td><td>Login username (unique)</td></tr><tr><td>Email</td><td>User email address</td></tr><tr><td>Password</td><td>Initial password</td></tr><tr><td>Role</td><td>Assign a built-in or custom role</td></tr><tr><td>Team</td><td>Assign to a DRM/catalog team (optional)</td></tr></tbody></table><p>The org is automatically set from the logged-in admin&#39;s organization.</p><h3 id="org-owner" tabindex="-1">Org owner <a class="header-anchor" href="#org-owner" aria-label="Permalink to &quot;Org owner&quot;">​</a></h3><p>The user who completes the first-time setup wizard is marked as <strong>Org Owner</strong>. Org owners are displayed with a badge in the Users list.</p><h3 id="password-reset" tabindex="-1">Password reset <a class="header-anchor" href="#password-reset" aria-label="Permalink to &quot;Password reset&quot;">​</a></h3><p>Admins can generate a password reset link from the user row (<strong>⋯ → Send reset link</strong>). The link is emailed to the user and expires after 24 hours.</p><hr><h2 id="sso" tabindex="-1">SSO <a class="header-anchor" href="#sso" aria-label="Permalink to &quot;SSO&quot;">​</a></h2><p>Enterprise builds support SSO provider configuration. See <a href="./sso">SSO</a>.</p><hr><h2 id="api-reference" tabindex="-1">API reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/users</code></td><td>List users</td></tr><tr><td><code>POST</code></td><td><code>/api/users</code></td><td>Create user</td></tr><tr><td><code>PUT</code></td><td><code>/api/users/:id</code></td><td>Update user</td></tr><tr><td><code>DELETE</code></td><td><code>/api/users/:id</code></td><td>Delete user</td></tr><tr><td><code>PUT</code></td><td><code>/api/users/:id/team</code></td><td>Assign team</td></tr><tr><td><code>POST</code></td><td><code>/api/auth/reset-password</code></td><td>Request password reset</td></tr><tr><td><code>GET</code></td><td><code>/api/admin/roles</code></td><td>List roles</td></tr><tr><td><code>POST</code></td><td><code>/api/admin/roles</code></td><td>Create role</td></tr><tr><td><code>PUT</code></td><td><code>/api/admin/roles/:id</code></td><td>Update role</td></tr><tr><td><code>DELETE</code></td><td><code>/api/admin/roles/:id</code></td><td>Delete role</td></tr></tbody></table>',37)])])}const m=e(o,[["render",s]]);export{p as __pageData,m as default};
